		const mq = window.matchMedia(`(min-width: ${MD_BREAKPOINT}px)`);
		const sync = () => setIsDesktop(mq.matches);
		sync();
		mq.addEventListener("change", sync);
		return () => mq.removeEventListener("change", sync);
	}, []);

	const isSearching = query.trim().length > 0;

