    className={`${actionButtonClass} hidden min-[480px]:inline-flex ${shareState === "copied" ? "text-primary" : ""} ${shareState === "error" ? "text-destructive" : ""}`}
    title={
      shareState === "copied"
        ? "Copied share link"
        : shareState === "error"
          ? "Could not share yet"
          : "Share session"
