async saveLessonPlan(topic: string, content: string, metadata?: Record<string, unknown>): Promise<LessonPlan> {
	const plan: LessonPlan = {
		id: this.generateId(),
		topic,
		createdAt: Date.now(),
		updatedAt: Date.now(),
		content,
		metadata,
	};
	await this.put(STORES.LESSON_PLANS, plan);
	return plan;
}

